import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Router } from '@angular/router';
import { map, tap } from 'rxjs/operators';
import { Subject } from 'rxjs';
import { apiKey, baseUrl } from 'src/environments/environment';
import { Posmanagement } from './interfaces/posmanagement.model';
import { AuthService } from 'src/app/auth/auth.service';

@Injectable({ providedIn: 'root' })
export class PosmanagementService {

    constructor(
        private http: HttpClient,
        private router: Router,
        private authService: AuthService
    ) { }
    
    async getActivitiesByUnit(unit_id: string) {
        return new Promise((resolve, reject) => {
            this.http.get(baseUrl + '/api/posadministration/getactivitiesbyunit/' + unit_id,
                {
                    headers: new HttpHeaders()
                        .set('Content-Type', 'application/json')
                })
                .subscribe(res => {
                    resolve(res);
                }, (err) => {
                    reject(err);
                });
        }); 
    }  

    async savePOS(posdata: any) {

        return new Promise((resolve, reject) => {

            this.http.post(baseUrl + '/api/posadministration',
                JSON.stringify(posdata),
                {
                    headers: new HttpHeaders()
                        .set('Content-Type', 'application/json')
                })
                .subscribe(res => {
                    resolve(res);
                }, (err) => {
                    reject(err);
                });
        });
    }
}